    let valid_business = ["electronics", "grocery", "pharmacy", "restaurant"];
    let mut valid_coupons = Vec::new();

    for i in 0..code.len() {
        if !isActive[i] {
            continue;
        }
        if code[i].is_empty() {
            continue;
        }
        if !code[i].chars().all(|c| c.is_ascii_alphanumeric() || c == '_') {
            continue;
        }
        if let Some(priority) = valid_business.iter().position(|&b| b == businessLine[i]) {
            valid_coupons.push((priority, code[i].clone()));
        }
    }

    valid_coupons.sort();

    valid_coupons.into_iter().map(|(_, s)| s).collect()
}
